+		return fmt.Errorf("invalid session name: %w", err)
+	}
+	pattern := monitorProcessPattern(session)
+	if strings.TrimSpace(pattern) == "" {
+		return errors.New("empty monitor process pattern")
+	}
+	return exec.Command("pkill", "-f", pattern).Run()
+}
